content.css:
* { box-sizing: border-box; margin: 0; padding: 0; }
html, body { font-family: -apple-system, "PingFang SC", "Microsoft YaHei", sans-serif; background: #faf7f2; color: #1f2937; height: 100%; }
#dash-root { padding: 16px; min-height: 100vh; }
.dash-loading { color: #6b7280; padding: 32px; text-align: center; }
.dash-header { margin-bottom: 16px; }
.dash-title { font-size: 20px; font-weight: 600; color: #1f2937; }
.dash-sub { font-size: 12px; color: #6b7280; margin-top: 4px; }
.kpi-row { display: grid; grid-template-columns: repeat(4, 1fr); gap: 12px; margin-bottom: 14px; }
.kpi-card { background: #ffffff; padding: 16px 18px; border-radius: 12px; border: 1px solid #e5e7eb; box-shadow: 0 1px 2px rgba(15,23,42,0.04); position: relative; overflow: hidden; }
.kpi-card::before { content: ''; position: absolute; top: 0; left: 0; right: 0; height: 3px; background: linear-gradient(90deg, #d97706 0%, #2563eb 100%); }
.kpi-label { font-size: 11px; color: #6b7280; margin-bottom: 8px; letter-spacing: 0.3px; }
.kpi-value { font-size: 28px; font-weight: 700; color: #111827; line-height: 1.1; font-variant-numeric: tabular-nums; }
.kpi-trend { font-size: 11px; color: #059669; margin-top: 6px; }
.kpi-trend.neutral { color: #6b7280; }
.kpi-trend.down { color: #dc2626; }
.grid-2 { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; margin-bottom: 12px; }
.grid-3 { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 12px; margin-bottom: 12px; }
.chart-card { background: #ffffff; border-radius: 12px; border: 1px solid #e5e7eb; padding: 14px 16px 10px; box-shadow: 0 1px 2px rgba(15,23,42,0.04); }
.chart-title { font-size: 13px; font-weight: 600; margin-bottom: 8px; color: #1f2937; display: flex; justify-content: space-between; align-items: center; }
.chart-title .tag { font-size: 10px; font-weight: 400; color: #6b7280; padding: 2px 6px; background: #f3f4f6; border-radius: 4px; }
.chart-body { width: 100%; height: 260px; }
.chart-body.h180 { height: 180px; }
.chart-body.h320 { height: 320px; }
table.dash-tbl { width: 100%; border-collapse: collapse; font-size: 12px; }
table.dash-tbl th { text-align: left; padding: 6px 10px; color: #6b7280; font-weight: 500; border-bottom: 1px solid #e5e7eb; font-size: 10px; letter-spacing: 0.3px; text-transform: uppercase; }
table.dash-tbl td { padding: 8px 10px; border-bottom: 1px solid #f3f4f6; color: #374151; }
table.dash-tbl tr:hover td { background: #fafaf7; }
.tag-pri { display: inline-block; padding: 2px 8px; border-radius: 4px; font-size: 10px; font-weight: 600; letter-spacing: 0.3px; }
.tag-pri.P0 { background: #fee2e2; color: #dc2626; }
.tag-pri.P1 { background: #fef3c7; color: #d97706; }
.tag-pri.P2 { background: #dbeafe; color: #2563eb; }
.tag-risk { display: inline-block; padding: 2px 8px; border-radius: 4px; font-size: 10px; }
.tag-risk.高风险 { background: #fee2e2; color: #dc2626; }
.tag-risk.中风险 { background: #fef3c7; color: #d97706; }
.tag-risk.正常 { background: #d1fae5; color: #059669; }
.tag-role { display: inline-block; padding: 2px 8px; border-radius: 4px; font-size: 10px; }
.tag-role.金牌导购 { background: #fef3c7; color: #d97706; }
.tag-role.普通导购 { background: #e5e7eb; color: #4b5563; }
.tag-role.新人导购 { background: #ddd6fe; color: #7c3aed; }
.tag-role.店长 { background: #d1fae5; color: #059669; }

/* ========== 移动端响应式 (BI ?pageRenderType=phoneView) ========== */
@media (max-width: 768px) {
  html, body { height: auto !important; overflow-y: auto !important; }
  #dash-root { padding: 10px; overflow-y: auto; -webkit-overflow-scrolling: touch; } /* iframe-mobile-scroll */
  .dash-header { margin-bottom: 10px; }
  .dash-title { font-size: 16px; }
  .dash-sub { font-size: 11px; }
  .kpi-row, .grid-2, .grid-3 { grid-template-columns: 1fr 1fr !important; gap: 8px !important; margin-bottom: 10px !important; }
  .kpi-card { padding: 10px 12px; border-radius: 8px; }
  .kpi-label { font-size: 10px; margin-bottom: 4px; }
  .kpi-value { font-size: 18px; }
  .kpi-trend { font-size: 10px; }
  .chart-card { padding: 10px 12px 6px; border-radius: 8px; }
  .chart-title { font-size: 12px; margin-bottom: 6px; }
  .chart-title .tag { font-size: 9px; padding: 1px 4px; }
  .chart-body { height: 200px !important; }
  .chart-body.h180 { height: 160px !important; }
  .chart-body.h220 { height: 180px !important; }
  .chart-body.h320 { height: 240px !important; }
  table.dash-tbl { font-size: 11px; }
  table.dash-tbl th { font-size: 9px; padding: 4px 6px; }
  table.dash-tbl td { padding: 5px 6px; }
  .chip-toolbar { padding: 6px 8px; font-size: 10px; gap: 2px; }
  .chip { padding: 3px 8px; font-size: 10px; margin: 0; }
}
@media (max-width: 480px) {
  .kpi-row { grid-template-columns: 1fr 1fr !important; }
  .grid-2 { grid-template-columns: 1fr !important; }
  .kpi-value { font-size: 16px; }
  .chart-body { height: 180px !important; }
  .chart-body.h180 { height: 150px !important; }
  .chart-body.h320 { height: 220px !important; }
}

content.script:
/**
 * 09 总览 (ECharts 重构)
 * 替代旧的 22 卡片混合"总览" 总览 → 6 dataView 全 ECharts 重构
 *
 * 6 dataViews:
 *   dv1: KPI (2 行: 直营/加盟 × 月营收/订单数/利润/利润率/堂食占比/客单价/门店数)
 *   dv2: 月度趋势 (4 行: 月份 × 总营收/堂食/外卖/利润/利润率)
 *   dv3: 城市效能对比 (35 行: 城市 × 营收/利润/利润率/堂食占比/门店数) → Top 10
 *   dv4: 9 类门店类型 (店型 × 营收/利润/利润率/堂食占比/客单价/门店数)
 *   dv5: 城市层级 × 月份 (4 层级 × 4 月 = 16 行: 营收/利润)
 *   dv6: 门店级 (1200+ 行)→ Top 10 标杆 + Bottom 10 改造
 */
(function autoBootstrap() {
  setTimeout(function() {
    try {
      var root = document.getElementById('dash-root');
      if (!root || root.innerText.indexOf('加载中') < 0) return;
      var cdId = 'u83cd012dd3d7403d6e1eb8e';
      fetch(window.parent.location.origin + '/api/card/' + cdId + '/data', {
        method: 'POST', headers: {'Content-Type': 'application/json'}, body: '{}',
        credentials: 'include',
      }).then(function(r){return r.json();}).then(function(j){
        if (!j.viewData) return;
        var data = j.viewData.map(function(v){return v.chartMain.columns;});
        if (typeof renderChart === 'function') renderChart(data, function(){}, {});
      });
    } catch(e) { console.error('autoBootstrap fail:', e); }
  }, 4000);
})();

function fmtNum(v) {
  if (v == null || isNaN(v)) return "—";
  v = Number(v);
  if (Math.abs(v) >= 1e8) return (v / 1e8).toFixed(2) + " 亿";
  if (Math.abs(v) >= 1e4) return (v / 1e4).toFixed(1) + " 万";
  return Math.round(v).toLocaleString();
}
function fmtPct(v, p) {
  if (v == null || isNaN(v)) return "—";
  return (Number(v) * 100).toFixed(p == null ? 1 : p) + "%";
}
function fmtMoney(v) {
  if (v == null || isNaN(v)) return "—";
  return "¥" + Math.round(Number(v)).toLocaleString();
}
function getCol(view, name) {
  if (!view) return null;
  for (var i = 0; i < view.length; i++) {
    if (view[i] && view[i].name === name) return view[i];
  }
  return null;
}
function sumCol(view, name) {
  var c = getCol(view, name);
  if (!c || !c.data) return 0;
  var s = 0;
  for (var k = 0; k < c.data.length; k++) s += Number(c.data[k] || 0);
  return s;
}
function avgCol(view, name) {
  var c = getCol(view, name);
  if (!c || !c.data) return 0;
  var s = 0, n = 0;
  for (var k = 0; k < c.data.length; k++) {
    var v = Number(c.data[k]);
    if (!isNaN(v)) { s += v; n++; }
  }
  return n ? s / n : 0;
}
function colArr(view, name) {
  var c = getCol(view, name);
  return (c && c.data) || [];
}

function renderChart(data, clickFunc, config) {
  var root = document.getElementById('dash-root');
  if (!root) return;
  if (!data || data.length < 6) {
    root.innerHTML = '<div class="dash-loading">No data (need 6 dataViews, got ' + (data && data.length) + ')</div>';
    return;
  }

  // ========== dv1 KPI ==========
  var dv1 = data[0];
  var totalRev = sumCol(dv1, "月营收");
  var totalOrders = sumCol(dv1, "订单数");
  var totalCt = sumCol(dv1, "店面贡献利润");
  var avgCtRate = avgCol(dv1, "店面贡献利润率");
  var avgDtRatio = avgCol(dv1, "堂食占比");
  var avgPrice = avgCol(dv1, "客单价");
  var totalStores = sumCol(dv1, "门店ID");

  // ========== dv2 月度趋势 ==========
  var dv2 = data[1];
  var months = colArr(dv2, "月份");
  var monthRev = colArr(dv2, "月营收").map(Number);
  var monthDt = colArr(dv2, "堂食营收").map(Number);
  var monthWm = colArr(dv2, "外卖营收").map(Number);
  var monthCt = colArr(dv2, "店面贡献利润").map(Number);
  var monthCtR = colArr(dv2, "店面贡献利润率").map(Number);

  // ========== dv3 城市效能 ==========
  var dv3 = data[2];
  var cityRows = (colArr(dv3, "城市")).map(function(c, i) {
    return {
      city: c,
      rev: Number(colArr(dv3, "月营收")[i] || 0),
      ct: Number(colArr(dv3, "店面贡献利润")[i] || 0),
      ctR: Number(colArr(dv3, "店面贡献利润率")[i] || 0),
      dt: Number(colArr(dv3, "堂食占比")[i] || 0),
      stores: Number(colArr(dv3, "门店ID")[i] || 0),
    };
  }).filter(function(r){return r.city;});
  cityRows.sort(function(a,b){return b.rev - a.rev;});
  var cityTop = cityRows.slice(0, 12);

  // ========== dv4 9 类门店类型 ==========
  var dv4 = data[3];
  var typeRows = colArr(dv4, "门店类型").map(function(t, i) {
    return {
      type: t,
      rev: Number(colArr(dv4, "月营收")[i] || 0),
      ct: Number(colArr(dv4, "店面贡献利润")[i] || 0),
      ctR: Number(colArr(dv4, "店面贡献利润率")[i] || 0),
      dt: Number(colArr(dv4, "堂食占比")[i] || 0),
      price: Number(colArr(dv4, "客单价")[i] || 0),
      stores: Number(colArr(dv4, "门店ID")[i] || 0),
    };
  }).filter(function(r){return r.type;}).sort(function(a,b){return b.rev - a.rev;});

  // ========== dv5 城市层级 × 月份 ==========
  var dv5 = data[4];
  var tiers = colArr(dv5, "城市层级");
  var tierMonths = colArr(dv5, "月份");
  var tierRev = colArr(dv5, "月营收").map(Number);
  // 透视: 月份 x 层级
  var monthSet = {}, tierSet = {};
  for (var i = 0; i < tiers.length; i++) {
    monthSet[tierMonths[i]] = 1;
    tierSet[tiers[i]] = 1;
  }
  var monthList = Object.keys(monthSet).sort();
  var tierList = ['一线','新一线','二线','三线'].filter(function(t){return tierSet[t];});
  var tierSeries = tierList.map(function(tier) {
    return {
      name: tier, type: 'bar', stack: 'tier',
      data: monthList.map(function(m) {
        for (var i = 0; i < tiers.length; i++) {
          if (tiers[i] === tier && tierMonths[i] === m) return tierRev[i];
        }
        return 0;
      }),
    };
  });

  // ========== dv6 门店标杆 + 改造 ==========
  var dv6 = data[5];
  var storeRows = colArr(dv6, "门店名称").map(function(s, i) {
    return {
      store: s,
      city: colArr(dv6, "城市")[i],
      type: colArr(dv6, "门店类型")[i],
      rev: Number(colArr(dv6, "月营收")[i] || 0),
      ct: Number(colArr(dv6, "店面贡献利润")[i] || 0),
      ctR: Number(colArr(dv6, "店面贡献利润率")[i] || 0),
    };
  }).filter(function(r){return r.store && r.rev > 1000;});
  storeRows.sort(function(a,b){return b.ctR - a.ctR;});
  var topStores = storeRows.slice(0, 10);
  var bottomStores = storeRows.slice(-10).reverse();

  // ========== 渲染 HTML ==========
  root.innerHTML = (
    '<div class="dash-header">' +
      '<div class="dash-title">📊 连锁咖啡经营总览 <span style="font-size:11px;color:#9ca3af;font-weight:400;">ECharts 重构 · 切换至 dws_单店利润月汇总</span></div>' +
      '<div class="dash-sub">把总盘、城市梯队、样板门店、改造队列压缩到一个 ECharts 重构的管理视图 · ' + totalStores + ' 门店</div>' +
    '</div>' +

    // KPI 6 个
    '<div class="kpi-row" style="grid-template-columns: repeat(6, 1fr);">' +
      '<div class="kpi-card">' +
        '<div class="kpi-label">总销售额</div>' +
        '<div class="kpi-value">' + fmtNum(totalRev) + '</div>' +
        '<div class="kpi-trend neutral">累计 4 月</div>' +
      '</div>' +
      '<div class="kpi-card">' +
        '<div class="kpi-label">总订单数</div>' +
        '<div class="kpi-value">' + fmtNum(totalOrders) + '</div>' +
        '<div class="kpi-trend neutral">全渠道</div>' +
      '</div>' +
      '<div class="kpi-card">' +
        '<div class="kpi-label">店面贡献利润率</div>' +
        '<div class="kpi-value">' + fmtPct(avgCtRate) + '</div>' +
        '<div class="kpi-trend' + (avgCtRate >= 0.15 ? '' : ' down') + '">' + (avgCtRate >= 0.15 ? '健康' : '需关注') + '</div>' +
      '</div>' +
      '<div class="kpi-card">' +
        '<div class="kpi-label">堂食占比</div>' +
        '<div class="kpi-value">' + fmtPct(avgDtRatio) + '</div>' +
        '<div class="kpi-trend neutral">高毛利业务</div>' +
      '</div>' +
      '<div class="kpi-card">' +
        '<div class="kpi-label">平均客单价</div>' +
        '<div class="kpi-value">' + fmtMoney(avgPrice) + '</div>' +
        '<div class="kpi-trend neutral">客均消费</div>' +
      '</div>' +
      '<div class="kpi-card">' +
        '<div class="kpi-label">门店总数</div>' +
        '<div class="kpi-value">' + totalStores + '</div>' +
        '<div class="kpi-trend neutral">9 类店型</div>' +
      '</div>' +
    '</div>' +

    // Row 1: 月度趋势 (营收堂食外卖 + 利润率) + 城市层级月份堆叠
    '<div class="grid-2">' +
      '<div class="chart-card">' +
        '<div class="chart-title">月度营收趋势 · 堂食 vs 外卖<span class="tag">渠道分流</span></div>' +
        '<div id="chart-monthly" class="chart-body h180"></div>' +
      '</div>' +
      '<div class="chart-card">' +
        '<div class="chart-title">城市层级 × 月份营收堆叠<span class="tag">下沉趋势</span></div>' +
        '<div id="chart-tier" class="chart-body h180"></div>' +
      '</div>' +
    '</div>' +

    // Row 2: 9 类店型矩阵 + 城市效能对比
    '<div class="grid-2">' +
      '<div class="chart-card">' +
        '<div class="chart-title">9 类门店类型 · 利润率分布<span class="tag">店型对标</span></div>' +
        '<div id="chart-type" class="chart-body h220"></div>' +
      '</div>' +
      '<div class="chart-card">' +
        '<div class="chart-title">Top 12 城市效能对比<span class="tag">营收 + 利润率</span></div>' +
        '<div id="chart-city" class="chart-body h220"></div>' +
      '</div>' +
    '</div>' +

    // Row 3: 门店级散点 (营收 vs 利润率) + 标杆/改造表
    '<div class="chart-card">' +
      '<div class="chart-title">门店效能散点矩阵 (营收 × 利润率 × 店型颜色)<span class="tag">' + storeRows.length + ' 家可分析门店</span></div>' +
      '<div id="chart-scatter" class="chart-body h320"></div>' +
    '</div>' +

    // Row 4: 标杆 + 改造表
    '<div class="grid-2">' +
      '<div class="chart-card">' +
        '<div class="chart-title">高利润率标杆门店 Top 10<span class="tag">复制打法</span></div>' +
        '<table class="dash-tbl">' +
          '<thead><tr><th>#</th><th>门店</th><th>城市</th><th>店型</th><th>月营收</th><th>贡献利润率</th></tr></thead>' +
          '<tbody>' +
            topStores.map(function(r, i) {
              return '<tr><td>' + (i+1) + '</td><td>' + (r.store || '—') + '</td><td>' + (r.city || '—') + '</td><td>' + (r.type || '—') +
                '</td><td>' + fmtNum(r.rev) + '</td><td><span class="tag-risk 正常">' + fmtPct(r.ctR) + '</span></td></tr>';
            }).join('') +
          '</tbody>' +
        '</table>' +
      '</div>' +
      '<div class="chart-card">' +
        '<div class="chart-title">低效门店改造清单 Bottom 10<span class="tag">优先介入</span></div>' +
        '<table class="dash-tbl">' +
          '<thead><tr><th>#</th><th>门店</th><th>城市</th><th>店型</th><th>月营收</th><th>贡献利润率</th></tr></thead>' +
          '<tbody>' +
            bottomStores.map(function(r, i) {
              return '<tr><td>' + (i+1) + '</td><td>' + (r.store || '—') + '</td><td>' + (r.city || '—') + '</td><td>' + (r.type || '—') +
                '</td><td>' + fmtNum(r.rev) + '</td><td style="color:' + (r.ctR < 0 ? '#dc2626' : '#d97706') + ';">' + fmtPct(r.ctR) + '</td></tr>';
            }).join('') +
          '</tbody>' +
        '</table>' +
      '</div>' +
    '</div>'
  );

  // ========== ECharts ==========
  // 月度趋势 - 双轴: 营收柱 + 利润率折线
  echarts.init(document.getElementById('chart-monthly')).setOption({
    tooltip: { trigger: 'axis', formatter: function(p) {
      var t = p[0].name + '<br/>';
      p.forEach(function(x) {
        t += x.marker + x.seriesName + ': ' +
          (x.seriesName === '利润率' ? (x.value*100).toFixed(1) + '%' : fmtNum(x.value)) + '<br/>';
      });
      return t;
    }},
    legend: { top: 0, textStyle: { fontSize: 10 } },
    grid: { left: 60, right: 60, top: 25, bottom: 30 },
    xAxis: { type: 'category', data: months, axisLabel: { fontSize: 10 } },
    yAxis: [
      { type: 'value', name: '营收', axisLabel: { formatter: fmtNum, fontSize: 10 } },
      { type: 'value', name: '利润率', axisLabel: { formatter: function(v){return (v*100).toFixed(0)+'%';}, fontSize: 10 }, max: function(v){return Math.max(0.3, v.max * 1.2);} },
    ],
    series: [
      { name: '堂食营收', type: 'bar', stack: 'rev', data: monthDt.map(function(v){return Math.round(v);}), itemStyle: { color: '#2563eb' } },
      { name: '外卖营收', type: 'bar', stack: 'rev', data: monthWm.map(function(v){return Math.round(v);}), itemStyle: { color: '#d97706' } },
      { name: '利润率', type: 'line', yAxisIndex: 1, data: monthCtR,
        itemStyle: { color: '#059669' }, lineStyle: { width: 2.5 },
        symbolSize: 8,
        label: { show: true, fontSize: 10, formatter: function(p){return (p.value*100).toFixed(1)+'%';} },
      },
    ],
  });

  // 城市层级堆叠
  echarts.init(document.getElementById('chart-tier')).setOption({
    tooltip: { trigger: 'axis', formatter: function(p) {
      var t = p[0].name + '<br/>';
      p.forEach(function(x){ t += x.marker + x.seriesName + ': ' + fmtNum(x.value) + '<br/>'; });
      return t;
    }},
    legend: { top: 0, textStyle: { fontSize: 10 } },
    grid: { left: 60, right: 20, top: 25, bottom: 30 },
    xAxis: { type: 'category', data: monthList, axisLabel: { fontSize: 10 } },
    yAxis: { type: 'value', axisLabel: { formatter: fmtNum, fontSize: 10 } },
    series: tierSeries.map(function(s, i) {
      var colors = ['#dc2626','#d97706','#2563eb','#059669'];
      return Object.assign(s, { itemStyle: { color: colors[i % 4] } });
    }),
  });

  // 9 类店型矩阵
  echarts.init(document.getElementById('chart-type')).setOption({
    tooltip: { trigger: 'axis', axisPointer: { type: 'shadow' }, formatter: function(p) {
      var t = p[0].name + '<br/>';
      p.forEach(function(x){
        var v = x.seriesName === '平均利润率' || x.seriesName === '堂食占比' ? (x.value*100).toFixed(1) + '%' :
          x.seriesName === '客单价' ? '¥' + Math.round(x.value) :
          x.seriesName === '门店数' ? x.value + ' 家' : fmtNum(x.value);
        t += x.marker + x.seriesName + ': ' + v + '<br/>';
      });
      return t;
    }},
    legend: { top: 0, textStyle: { fontSize: 10 } },
    grid: { left: 60, right: 60, top: 25, bottom: 40 },
    xAxis: { type: 'category', data: typeRows.map(function(r){return r.type;}), axisLabel: { fontSize: 10, interval: 0, rotate: 20 } },
    yAxis: [
      { type: 'value', name: '营收', axisLabel: { formatter: fmtNum, fontSize: 10 } },
      { type: 'value', name: '利润率', axisLabel: { formatter: function(v){return (v*100).toFixed(0)+'%';}, fontSize: 10 } },
    ],
    series: [
      { name: '月营收', type: 'bar', data: typeRows.map(function(r){return Math.round(r.rev);}), itemStyle: { color: '#2563eb' } },
      { name: '平均利润率', type: 'line', yAxisIndex: 1, data: typeRows.map(function(r){return r.ctR;}),
        itemStyle: { color: function(p){ return p.value >= 0.20 ? '#059669' : p.value >= 0.10 ? '#d97706' : '#dc2626'; } },
        lineStyle: { width: 2.5, color: '#d97706' }, symbolSize: 10,
        label: { show: true, fontSize: 10, formatter: function(p){return (p.value*100).toFixed(1)+'%';} },
      },
    ],
  });

  // Top 城市效能
  echarts.init(document.getElementById('chart-city')).setOption({
    tooltip: { trigger: 'axis', formatter: function(p) {
      var t = p[0].name + '<br/>';
      p.forEach(function(x){
        var v = x.seriesName === '利润率' || x.seriesName === '堂食占比' ? (x.value*100).toFixed(1) + '%' : fmtNum(x.value);
        t += x.marker + x.seriesName + ': ' + v + '<br/>';
      });
      return t;
    }},
    legend: { top: 0, textStyle: { fontSize: 10 } },
    grid: { left: 80, right: 70, top: 25, bottom: 40 },
    xAxis: { type: 'category', data: cityTop.map(function(r){return r.city;}), axisLabel: { fontSize: 10, interval: 0, rotate: 30 } },
    yAxis: [
      { type: 'value', name: '营收', axisLabel: { formatter: fmtNum, fontSize: 10 } },
      { type: 'value', name: '利润率', axisLabel: { formatter: function(v){return (v*100).toFixed(0)+'%';}, fontSize: 10 } },
    ],
    series: [
      { name: '月营收', type: 'bar', data: cityTop.map(function(r){return Math.round(r.rev);}), itemStyle: { color: '#2563eb' } },
      { name: '利润率', type: 'line', yAxisIndex: 1, data: cityTop.map(function(r){return r.ctR;}),
        itemStyle: { color: '#059669' }, lineStyle: { width: 2.5 }, symbolSize: 8,
      },
    ],
  });

  // 散点图: 营收 vs 利润率, 颜色按店型, 大小按订单数
  var typeColorMap = {
    '快取店':'#059669','商场店':'#2563eb','社区店':'#9333ea','写字楼店':'#06b6d4',
    '学校店':'#22c55e','交通店':'#d97706','外卖卫星店':'#f97316','旗舰店':'#dc2626','夜市店':'#a855f7',
  };
  var scatterByType = {};
  storeRows.forEach(function(r) {
    var t = r.type || '其他';
    if (!scatterByType[t]) scatterByType[t] = [];
    scatterByType[t].push([r.rev, r.ctR, r.store, r.city]);
  });
  echarts.init(document.getElementById('chart-scatter')).setOption({
    tooltip: { trigger: 'item', formatter: function(p) {
      var d = p.data;
      return d[2] + ' (' + d[3] + ')<br/>' +
        '月营收: ' + fmtNum(d[0]) + '<br/>' +
        '利润率: ' + (d[1]*100).toFixed(1) + '%<br/>' +
        '店型: ' + p.seriesName;
    }},
    legend: { top: 0, type: 'scroll', textStyle: { fontSize: 10 } },
    grid: { left: 70, right: 20, top: 35, bottom: 40 },
    xAxis: { type: 'value', name: '月营收', axisLabel: { formatter: fmtNum, fontSize: 10 }, nameGap: 25 },
    yAxis: { type: 'value', name: '利润率', axisLabel: { formatter: function(v){return (v*100).toFixed(0)+'%';}, fontSize: 10 } },
    series: Object.keys(scatterByType).map(function(t) {
      return {
        name: t, type: 'scatter', symbolSize: 6,
        data: scatterByType[t],
        itemStyle: { color: typeColorMap[t] || '#6b7280', opacity: 0.6 },
      };
    }),
  });

  window.addEventListener('resize', function() {
    ['chart-monthly','chart-tier','chart-type','chart-city','chart-scatter'].forEach(function(id) {
      var el = document.getElementById(id);
      if (el && echarts.getInstanceByDom(el)) echarts.getInstanceByDom(el).resize();
    });
  });
}
